use std::time::{Duration, Instant};

struct WebhookDispatcher {
    max_retries: u32,
    initial_delay: Duration,
}

impl WebhookDispatcher {
    fn new(max_retries: u32, initial_delay: Duration) -> Self {
        WebhookDispatcher { max_retries, initial_delay }
    }

    async fn dispatch_webhook(&self, url: &str) -> Result<(), String> {
        for attempt in 0..=self.max_retries {
            if attempt > 0 {
                let delay = self.calculate_backoff(attempt);
                println!("Attempt {} failed. Waiting for {:?} before retrying...", attempt + 1, delay);
                tokio::time::sleep(delay).await;
            }

            match self.send_request(url).await {
                Ok(_) => {
                    println!("Successfully dispatched webhook to {}. Total attempts: {}", url, attempt + 1);
                    return Ok(())
                },
                Err(e) => {
                    if attempt == self.max_retries {
                        return Err(format!("Failed after {} attempts. Last error: {}", self.max_retries + 1, e));
                    }
                }
            }
        }
        Ok(())
    }

    async fn send_request(&self, url: &str) -> Result<(), String> {
        println!("--- Sending request to {} ---", url);
        static mut ATTEMPTS_MADE: u32 = 0;
        unsafe {
            ATTEMPTS_MADE += 1;
            if ATTEMPTS_MADE < 3 {
                return Err(format!("Simulated connection failure for {}", url));
            }
        }
        Ok(())
    }

    fn calculate_backoff(&self, attempt: u32) -> Duration {
        let exponential_factor = 2u32.pow(attempt - 1);
        self.initial_delay.checked_mul(exponential_factor).unwrap()
    }
}

