use std::collections::HashMap;
use std::net::SocketAddr;

struct DnsResolver {
    cache: HashMap<String, SocketAddr>,
}

impl DnsResolver {
    fn new() -> Self {
        DnsResolver { cache: HashMap::new() }
    }

    fn resolve_address(&mut self, service_name: &str) -> Result<SocketAddr, String> {
        if let Some(addr) = self.cache.get(service_name) {
            return Ok(*addr);
        }

        println!("Attempting to perform external DNS lookup for: {}", service_name);

        match service_name {
            "api.example.com" => {
                let result = std::net::ToSocketAddrs::to_socket_addrs("api.example.com:80").unwrap().next();
                if let Some(addr) = result {
                    self.cache.insert(service_name.to_string(), addr);
                    Ok(addr)
                } else {
                    Err(format!("Could not resolve IP for {}", service_name))
                }
            }
            "auth.internal:443" => {
                let result = std::net::ToSocketAddrs::to_socket_addrs("auth.internal:443").unwrap().next();
                if let Some(addr) = result {
                    self.cache.insert(service_name.to_string(), addr);
                    Ok(addr)
                } else {
                    Err(format!("Could not resolve IP for {}", service_name))
                }
            }
            _ => Err(format!("Unknown service name: {}", service_name)),
        }
    }
}

fn main() {
    let mut resolver = DnsResolver::new();

    match resolver.resolve_address("api.example.com") {
        Ok(addr) => println!("Successfully resolved '{}' to: {}", "api.example.com", addr),
        Err(e) => eprintln!("Error resolving 'api.example.com': {}", e),
    }

    match resolver.resolve_address("auth.internal:443") {
        Ok(addr) => println!("Successfully resolved 'auth.internal:443' to: {}", addr),
