    }

    match resolver.resolve_address("unknown.host") {
        Ok(_) => println!("Should not happen."),
        Err(e) => println!("Correctly failed to resolve 'unknown.host': {}", e),
    }
}

use std::collections::VecDeque;
use std::sync::{Mutex, Arc};

struct EmailQueue {
    queue: Mutex<VecDeque<String>>,
}

impl EmailQueue {
    fn new() -> Self {
        EmailQueue { 
            queue: Mutex::new(VecDeque::new()) 
        }
    }

    fn add_email(&self, address: String) {
        let mut q = self.queue.lock().unwrap();
        q.push_back(address);
    }

    fn process_next_batch(&self) -> Vec<String> {
        let mut q = self.queue.lock().unwrap();
        let count = q.len().min(3);
        let mut emails_to_deliver = Vec::with_capacity(count);
        for _ in 0..count {
            if let Some(email) = q.pop_front() {
                emails_to_deliver.push(email);
            }
        }
        emails_to_deliver
    }
}

fn main() {
    let queue = Arc::new(EmailQueue::new());

    queue.add_email("userA@local.net".to_string());
    queue.add_email("userB@local.net".to_string());
    queue.add_email("userC@local.net".to_string());
    queue.add_email("userD@local.net".to_string());

    let queue_clone = Arc::clone(&queue);
    std::thread::spawn(move || {
        println!("Thread 1: Starting delivery cycle.");
        let batch = queue_clone.process_next_batch();
        println!("Delivered batch from Thread 1: {:?}", batch);
    });

    std::thread::sleep(std::time::Duration::from_millis(50));

    let queue_clone2 = Arc::clone(&queue);
    std::thread::spawn(move || {
        println!("Thread 2: Starting delivery cycle.");
        let batch = queue_clone2.process_next_batch();
        println!("Delivered batch from Thread 2: {:?}", batch);
    });

    std::thread::sleep(std::time::Duration::from_millis(100));
    println!("Main thread finished processing.");
}

