        eprintln!("Usage: {} <hostname>", arguments[0]);
        return Ok(())
    }

    let hostname = &arguments[1];

    match hostname.to_socket_addrs() {
        Ok(addresses) => {
            println!("Successfully resolved hostname:");
            for address in addresses.take(5) { 
                println!("  - IP Address: {} (Port: 0)", address.ip());
            }
        },
        Err(e) => {
            eprintln!("Failed to resolve hostname: {}", e);
        }
    }

    Ok(())
}
